class Block {
	constructor(blockID, blockEntityData, blockVersion){
		[, this.nameSpace, this.id, this.states, this.version]=blockID.match(/^(?:([a-zA-Z0-9_]*):)?([A-Za-z0-9_]+)(\[.+\])?@?(\d+)?/);
		this.blockEntityData=blockEntityData;
		if(blockVersion!==undefined) this.version=blockVersion;
	}
}

class IndexedBlock {
	constructor(blockIndex, blockEntityData){
		this.Index=blockIndex;
		this.blockEntityData=blockEntityData;
	}
}

class Matrix {
	constructor(X=0, Y=0, Z=0, sizeLock=false, palette=[]){
		this.Xmax=X;
		this.Ymax=Y;
		this.Zmax=Z;
		this.sizeLock=sizeLock;
		this.blocks=[];
		this.palette=palette;
		this.xOffset=0;
		this.yOffset=0;
		this.zOffset=0;
	}
	
	setBlock(rx, ry, rz, block, overwrite=true){
		if(this.sizeLock&&(rx<0||ry<0||rz<0)) throw new Error("Minus block position not available in locked size!");
		let x,y,z;
		if(rx<-this.xOffset) {
			for(;rx<-this.xOffset;this.blocks.unshift([])) this.xOffset++,this.Xmax++;
			x=0;
		}else{
			x=rx+this.xOffset;
		}
		if(ry<-this.yOffset) {
			for(;ry<-this.yOffset;){
				for(let i in this.blocks){
					this.blocks[i].unshift([]);
				}
				this.yOffset++;
				this.Ymax++;
			}
			y=0;
		}else{
			y=ry+this.yOffset;
		}
		if(rz<-this.zOffset) {
			for(;rz<-this.zOffset;){
				for(let i in this.blocks){
					for(let j in this.blocks[i]){
						this.blocks[i][j].unshift();
					}
				}
				this.zOffset++;
				this.Zmax++;
			}
			z=0;
		}else{
			z=rz+this.zOffset;
		}


		if(this.sizeLock&&(x>this.Xmax-1|y>this.Ymax-1|z>this.Zmax-1)) throw new Error("Block out of the locked size!");
		this.Xmax=this.Xmax>x+1?this.Xmax:x+1;
		this.Ymax=this.Ymax>y+1?this.Ymax:y+1;
		this.Zmax=this.Zmax>z+1?this.Zmax:z+1;
		if(typeof(this.blocks[x])==='undefined') this.blocks[x]=[];
		if(typeof(this.blocks[x][y])==='undefined') this.blocks[x][y]=[];
		if(this.blocks[x][y][z]&&!overwrite) throw new Error("Already set a block in this position!");
		if(typeof(block.Index)=="number") {this.blocks[x][y][z]=block;return};
		let id=block.id.trim(),blockStatesString=block.states?(block.states.replaceAll(/\s+/g,'').match(/\[(.+)\]/)||['',''])[1].split(",").toSorted().join(','):'';
		let paletteID=(blockStatesString?`${block.nameSpace||"minecraft"}:${id}[${blockStatesString}]`:`${block.nameSpace||"minecraft"}:${id}`)+(block.version===undefined?'':`@${block.version}`);
		if(!this.palette.includes(paletteID)){
			this.blocks[x][y][z]=new IndexedBlock(this.addPalette(paletteID)-1,block.blockEntityData);
		}else{
			this.blocks[x][y][z]=new IndexedBlock(this.palette.indexOf(paletteID),block.blockEntityData);
		}
	}

	modifyBlock(rx, ry, rz, processor=()=>{}){
		let x=rx+this.xOffset,y=ry+this.yOffset,z=rz+this.zOffset;
		if(this.blocks[x]?.[y]?.[z]===undefined) return false;
		let block=new Block(this.palette[this.blocks[x][y][z].Index],this.blocks[x][y][z].blockEntityData);
		let operation=processor(block);
		if(operation==false) delete this.blocks[x][y][z];
		else this.setBlock(rx, ry, rz, block);
	}
		
	
	getBlock(rx, ry, rz){
		let x=rx+this.xOffset,y=ry+this.yOffset,z=rz+this.zOffset;
		return this.blocks[x]?.[y]?.[z];
	}
	
	addPalette(block){
		return this.palette.push(block);
	}
	
	/*generatePalette(){
		if(this.paletteMode) return;
		let blocks={};
		let paletteIndex=0;
		for(let i of this.getAllBlocks()){
			let id,blockStatesString;
			if(!blocks[id=i.block.id.replace("mineraft:",'').trim()]) blocks[id]=[];
			if(!blocks[id].includes(blockStatesString=i.block.states.replaceAll(/\s+/g,'').match(/\[(.+)\]/)[1].split(",").toSorted().join(','))) blocks[id].push(blockStatesString);
		}
	}*/
	getAllBlocks(sx, sy, sz, dx, dy, dz){
		let Xbegin,Ybegin,Zbegin;
		if(typeof(sx)==='undefined') Xbegin=0;
		else Xbegin=sx+this.xOffset;
		if(typeof(sy)==='undefined') Ybegin=0;
		else Ybegin=sy+this.yOffset;
		if(typeof(sz)==='undefined') Zbegin=0;
		else Zbegin=sz+this.zOffset;
		let Xend,Yend,Zend;
		if(typeof(dx)==='undefined') Xend=this.Xmax-1+this.xOffset;
		else Xend=dx+this.xOffset;
		if(typeof(dy)==='undefined') Yend=this.Ymax-1+this.yOffset;
		else Yend=dy+this.yOffset;
		if(typeof(dz)==='undefined') Zend=this.Zmax-1+this.zOffset;
		else Zend=dz+this.zOffset;
		let result=[];
		for(let x in this.blocks){
			if((x>Xend)|(x<Xbegin)) continue;
			for(let y in this.blocks[x]){
				if((y>Yend)|(y<Ybegin)) continue;
				for(let z in this.blocks[x][y]){
					if((z>Zend)|(z<Zbegin)) continue;
					if(!this.blocks[x][y][z]) continue;
					result.push({
						block: this.blocks[x][y][z],
						x: x-this.xOffset,
						y: y-this.yOffset,
						z: z-this.zOffset
					})
				}
			}
		}
		return result;
	}
}


