function blockStatesString2blockStates(blockStatesString){
	if(!blockStatesString) return;
	let blockStates={"type":"compound","value":{}};
	for(let i of blockStatesString.split(',')){
		let state=i.split(/[:=]/);
		if(/^\s*\d+\s*$/.test(state[1])){
			blockStates.value[state[0].match(/\"?([^\"]+)\"?/)[1]]={type: "int", value: parseInt(state[1])};
		}else if(/\s*(true|false|none)\s*/.test(state[1])){
			blockStates.value[state[0].match(/\"?([^\"]+)\"?/)[1]]={type: "byte", value: Number(/\s*(true)\s*/.test(state[1]))};
		}else if(typeof state[1].match(/\"?(.*)\"?/)[1]!=='undefined'){
			blockStates.value[state[0].match(/\"?([^\"]+)\"?/)[1]]={type: "string", value: state[1].match(/\"(.*)\"/)[1]};
		}else{
			console.log(blockStatesString,i,state)
			throw new Error("Unknown type!")
		}
	}
	return blockStates;
}


function blockStates2blockStatesString(states){
	if(!states) return '';
	let blockStatesString=''
	for(let i in (states.value)||states){
		if (blockStatesString) blockStatesString+=',';
		blockStatesString+=`"${i}"=`+(((states.value)||states)[i].type==="string"?`"${((states.value)||states)[i].value}"`:(((states.value)||states)[i].type==="byte"?Boolean(((states.value)||states)[i].value).toString():((states.value)||states)[i].value.toString()));
	}
	if(!blockStatesString) return '';
	return `[${blockStatesString}]`;
}

function object2NBTJSON(obj){
	let result={};
	for(let i in obj){
		if(typeof(obj[i])=='boolean'){
			result[i]={
				"type": "byte",
				"value": obj[i]
			}
			continue;
		}
		if(typeof(obj[i])=='string'){
			result[i]={
				"type": "string",
				"value": obj[i]
			}
			continue;
		}
		if(typeof(obj[i])=='number'&&!(obj[i]%1)){
			result[i]={
				"type": "int",
				"value": obj[i]
			}
			continue;
		}
		if(typeof(obj[i])=='object'){
			result[i]={
				"type": "compound",
				"value": object2NBTJSON(obj[i])
			}
			continue;
		}
		//先做这些 剩下的不怎么常用到
		//如果真的有 报错
		console.log(obj[i])
		throw new Error("Unsupported type!")
	}
	return result;
}

function blockData2blockStates(blockID,data=0){
	blockID=blockID.trim();
	let result=(data2block[blockID.replace("minecraft:", '')]||[])[data];
	if(!result) console.error(blockID,data);
	return result||blockID;
}




